# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import SwiftUI
import FirebaseDynamicLinks

struct ContentView: View {
    @State private var promoCode: String = ""
    @State private var discountPercentage: Int = 0

    var body: some View {
        Text("Promo Code: \(promoCode)")
            .padding()
        Text("Discount Percentage: \(discountPercentage)")
            .padding()
    }

    func handleUniversalLink(url: URL) {
        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        guard let queryItems = components?.queryItems else {
            return
        }

        for item in queryItems {
            switch item.name {
            case "code":
                promoCode = item.value!
            case "discount":
                discountPercentage = Int(item.value!) ?? 0
            }
        }
    }
}

struct ContentView_Previews: PreviewProvider {
    static var previews: some View {
        ContentView()
    }
}

extension AppDelegate: DynamicLinksDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity) -> Bool {
        if let url = userActivity.webpageURL {
            let contentView = ContentView()
            contentView.handleUniversalLink(url: url)
        }
        return true
    }
}